import{_ as a,o as r,c as e,a2 as o}from"./chunks/framework.DIMps2S2.js";const b=JSON.parse('{"title":"联系客服","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"troubleshooting/contact-support.md","filePath":"zh-CN/troubleshooting/contact-support.md"}'),i={name:"troubleshooting/contact-support.md"};function l(d,t,n,h,s,c){return r(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="联系客服" tabindex="-1">联系客服 <a class="header-anchor" href="#联系客服" aria-label="Permalink to &quot;联系客服&quot;">​</a></h1><p>在线客服、客服热线、电子邮件联系方式及联系前建议准备的信息。</p><h2 id="在线客服-推荐" tabindex="-1">在线客服（推荐） <a class="header-anchor" href="#在线客服-推荐" aria-label="Permalink to &quot;在线客服（推荐）&quot;">​</a></h2><p><strong>长桥 App → 我的 → 帮助与客服 → 在线客服</strong></p><p>支持中文、英文，工作时间内由人工客服接待，非工作时间可留言。</p><h2 id="客服热线" tabindex="-1">客服热线 <a class="header-anchor" href="#客服热线" aria-label="Permalink to &quot;客服热线&quot;">​</a></h2><table tabindex="0"><thead><tr><th>地区</th><th>电话</th><th>服务时间</th></tr></thead><tbody><tr><td>中国大陆</td><td>4000712688</td><td>工作日 09:00–18:00（北京时间）</td></tr><tr><td>香港</td><td>+852 3898 3098</td><td>工作日 09:00–18:00（HKT）</td></tr><tr><td>新加坡</td><td>+65 6950 0118</td><td>工作日 09:00–18:00（SGT）</td></tr></tbody></table><h2 id="电子邮件" tabindex="-1">电子邮件 <a class="header-anchor" href="#电子邮件" aria-label="Permalink to &quot;电子邮件&quot;">​</a></h2><table tabindex="0"><thead><tr><th>账户类型</th><th>邮箱地址</th></tr></thead><tbody><tr><td>香港综合账户相关</td><td><a href="mailto:service@longbridge.hk" target="_blank" rel="noreferrer">service@longbridge.hk</a></td></tr><tr><td>新加坡综合账户相关</td><td><a href="mailto:contact@longbridge.sg" target="_blank" rel="noreferrer">contact@longbridge.sg</a></td></tr></tbody></table><p>邮件回复通常在 1–2 个工作日内。</p><h2 id="联系客服前建议准备" tabindex="-1">联系客服前建议准备 <a class="header-anchor" href="#联系客服前建议准备" aria-label="Permalink to &quot;联系客服前建议准备&quot;">​</a></h2><p>提前准备以下信息有助于更快解决问题：</p><ul><li><strong>账户号码</strong>（以 H 或 SG 开头）</li><li><strong>问题描述</strong>：具体操作步骤、出现的错误提示</li><li><strong>截图</strong>：App 截图或错误页面截图</li><li><strong>时间</strong>：问题发生的具体时间</li></ul><h2 id="相关排查文档" tabindex="-1">相关排查文档 <a class="header-anchor" href="#相关排查文档" aria-label="Permalink to &quot;相关排查文档&quot;">​</a></h2><p>部分问题可通过以下文档自助排查：</p><ul><li><a href="/wiki/troubleshooting/入金未到账怎么办">入金未到账怎么办</a></li><li><a href="/wiki/troubleshooting/出金失败怎么办">出金失败怎么办</a></li><li><a href="/wiki/troubleshooting/订单提交失败怎么办">订单提交失败怎么办</a></li><li><a href="/wiki/troubleshooting/login-failure">App 登录失败怎么办</a></li><li><a href="/wiki/troubleshooting/收不到短信验证码">收不到短信验证码</a></li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/troubleshooting">故障排查</a></li></ul>',18)])])}const p=a(i,[["render",l]]);export{b as __pageData,p as default};
